CREATE TABLE IF NOT EXISTS t_p61016064_digital_innovation_i.wb_ai_opportunities (id SERIAL PRIMARY KEY, case_id INTEGER NOT NULL, user_id INTEGER NOT NULL, process_step_id INTEGER, title TEXT NOT NULL, current_manual_operation TEXT, data_type TEXT NOT NULL DEFAULT 'mixed', proposed_solution_type TEXT NOT NULL DEFAULT 'none', use_case_type TEXT, expected_effect TEXT, required_data TEXT, quality_requirements TEXT, risks TEXT, security_notes TEXT, human_in_loop BOOLEAN NOT NULL DEFAULT TRUE, recommendation TEXT NOT NULL DEFAULT 'assess', is_archived BOOLEAN NOT NULL DEFAULT FALSE, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()); CREATE INDEX IF NOT EXISTS idx_wb_ai_case ON t_p61016064_digital_innovation_i.wb_ai_opportunities(case_id);